promise new Promise((resolve) => {
    const emptyContainer = {
      get: () => Promise.resolve(() => ({})),
      init: () => {}
    }

    const remoteUrl = window.StudioUIBundleRemoteUrl

    if (!remoteUrl) {
      throw new Error('Required remote "pimcore_studio_ui_bundle" is not available');
      return
    }

    // Check if the container is already available
    if (window['pimcore_studio_ui_bundle']) {
      resolve({
        get: (request) => window['pimcore_studio_ui_bundle'].get(request),
        init: (...arg) => {
          try {
            return window['pimcore_studio_ui_bundle'].init(...arg)
          } catch(e) {
            console.log('remote container already initialized')
          }
        }
      })
      return
    }

    const script = document.createElement('script')
    script.src = remoteUrl
    script.onload = () => {
      const proxy = {
        get: (request) => window['pimcore_studio_ui_bundle'].get(request),
        init: (...arg) => {
          try {
            return window['pimcore_studio_ui_bundle'].init(...arg)
          } catch(e) {
            console.log('remote container already initialized')
          }
        }
      }
      resolve(proxy)
    }
    script.onerror = () => {
      throw new Error('Failed to load required remote "pimcore_studio_ui_bundle" from ' + remoteUrl);
    }
    document.head.appendChild(script);
  })

